WITH s AS (
  SELECT *
  FROM public.seasons
  ORDER BY id DESC
  LIMIT 1
)
SELECT public.refresh_team_power_ratings(
  (SELECT startDate FROM s),
  LEAST(
    (now() AT TIME ZONE 'America/New_York')::date,
    (SELECT regularSeasonEndDate FROM s)
  )
);
